import React, { useState, useEffect } from 'react';

function App() {
  const roomOptions = ['Room A', 'Room B', 'Room C'];
  const [bookings, setBookings] = useState([]);
  const [roomId, setRoomId] = useState('');
  const [startTime, setStartTime] = useState('');
  const [endTime, setEndTime] = useState('');
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchBookings();
  }, []);

  const fetchBookings = async () => {
    try {
      const response = await fetch('http://localhost:5000/bookings');
      if (!response.ok) {
        throw new Error('Failed to load bookings');
      }
      const data = await response.json();
      setBookings(data);
      setError(null);
    } catch (err) {
      console.error(err);
      setError(err.message);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      const response = await fetch('http://localhost:5000/bookings', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          roomId,
          startTime: new Date(startTime),
          endTime: new Date(endTime),
        }),
      });

      const result = await response.json();
      if (!response.ok) {
        throw new Error(result.message || 'Booking failed');
      }

      setRoomId('');
      setStartTime('');
      setEndTime('');
      setError(null);
      await fetchBookings();
    } catch (err) {
      console.error(err);
      setError(err.message);
    }
  };

  return (
    <div className="min-h-screen bg-gray-100">
      <nav className="bg-blue-600 text-white p-4 shadow-md">
        <h1 className="text-xl font-bold">Meeting Room Booking</h1>
      </nav>
      <div className="container mx-auto p-4">
        <form onSubmit={handleSubmit} className="bg-white p-6 rounded-lg shadow-md mb-8">
          <h2 className="text-lg font-semibold mb-4">Book a Room</h2>
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
            <select
              value={roomId}
              onChange={e => setRoomId(e.target.value)}
              required
              className="border border-gray-300 p-2 rounded"
            >
              <option value="">Select Room</option>
              {rooms.map(room => (
                <option key={room._id} value={room._id}>{room.name}</option>
              ))}
            </select>
            <input
              type="datetime-local"
              value={startTime}
              onChange={e => setStartTime(e.target.value)}
              required
              className="border border-gray-300 p-2 rounded"
            />
            <input
              type="datetime-local"
              value={endTime}
              onChange={e => setEndTime(e.target.value)}
              required
              className="border border-gray-300 p-2 rounded"
            />
            <button
              type="submit"
              className="bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700"
            >
              Book
            </button>
          </div>
        </form>
        <div className="bg-white p-6 rounded-lg shadow-md">
          <h2 className="text-lg font-semibold mb-4">All Bookings</h2>
          <div className="overflow-x-auto">
            <table className="w-full table-auto border-collapse border border-gray-300">
              <thead>
                <tr className="bg-gray-200">
                  <th className="border border-gray-300 p-2 text-left">Room ID</th>
                  <th className="border border-gray-300 p-2 text-left">Start Time</th>
                  <th className="border border-gray-300 p-2 text-left">End Time</th>
                  <th className="border border-gray-300 p-2 text-left">Booked At</th>
                </tr>
              </thead>
              <tbody>
                {bookings.map(booking => (
                  <tr key={booking._id} className="hover:bg-gray-50">
                    <td className="border border-gray-300 p-2">{booking.roomId}</td>
                    <td className="border border-gray-300 p-2">{new Date(booking.startTime).toLocaleString()}</td>
                    <td className="border border-gray-300 p-2">{new Date(booking.endTime).toLocaleString()}</td>
                    <td className="border border-gray-300 p-2">{new Date(booking.bookedAt).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}

export default App;
